const allData = $("Credilus Request").first().json.data;
const record = allData[0];

const emails = record.EMAILS;
const nomeCompleto = record.NOME || "";
const cpf = record.CPFCNPJ || "";

function parseEmailList(emailString) {
  if (emailString) {
    return emailString
      .split(',')
      .map(email => email.trim())
      .filter(email => email !== '');
  }
  return [];
}

let emailList = parseEmailList(emails);

if (emailList.length === 0) {
  const nomes = nomeCompleto.trim().split(" ");
  const primeiroNome = nomes[0]?.toLowerCase() || "usuario";
  const ultimoNome = nomes[nomes.length - 1]?.toLowerCase() || "padrao";
  const cpfDigitos = cpf.replace(/\D/g, ""); // remove caracteres não numéricos
  const ultimosDigitos = cpfDigitos.slice(-2) || "00";
  const emailGerado = `${primeiroNome}${ultimoNome}${ultimosDigitos}@gmail.com`;
  emailList = [emailGerado];
}

return {
  emails: emailList
};

const phoneData = $("Get Body").first().json.remoteJid;

function extractPhoneInfo(whatsappString) {
    const match = whatsappString?.match(/^55(\d{2})(\d{8,9})@s\.whatsapp\.net$/);

    if (match) {
        return {
            ddd: match[1],
            phone: match[2]
        };
    }

    return null; // Retorna null se o formato não corresponder
}

const result = extractPhoneInfo(phoneData);

// O n8n espera um array de objetos como saída no nó de código
return result ? [result] : [];

const items = $input.all();

// Verifica se há um aprovado (presença de CPF)
const aprovado = items.find(i => i.json.cpf);

// Se houver um aprovado, retorna ele diretamente
if (aprovado) {
  return [{ json: aprovado.json }];
}

// Se não houver aprovados, consolida os recusados corretamente
const recusados = items
  .map(i => i.json.data) // Acessa o array "data"
  .flat() // Une os arrays internos
  .filter(i => i && i.status_code !== '200'); // Remove valores nulos/vazios e filtra recusados

// Se houver recusados, retorna apenas um (o primeiro)
if (recusados.length > 0) {
  return [{ json: recusados[0] }];
}

// Se não houver dados disponíveis, retorna uma mensagem simples
return [{ json: { message: "Nenhuma informação disponível." } }];

return $input.all().map(item => {
    const caminho = item.json["soapenv:Envelope"]["soapenv:Body"]["ns1:buscarCartoesDisponiveisResponse"]
        .buscarCartoesDisponiveisReturn.cartoesRetorno.cartoesRetorno;

    return Array.isArray(caminho) ? caminho.map(c => ({ json: c })) : [{ json: caminho }];
}).flat();

const rawMessage = items[0].json.message;

let mensagemFinal = "";

// Tenta fazer parsing como JSON se for uma string entre aspas
let parsed;
try {
  parsed = JSON.parse(rawMessage);
} catch (e) {
  parsed = null;
}

if (parsed && typeof parsed === 'string') {
  // Tentativa de extrair <faultstring> do XML
  const match = parsed.match(/<faultstring>(.*?)<\/faultstring>/);
  if (match && match[1]) {
    const xmlEncodedMessage = match[1];

    // Decodifica entidades HTML (ex: &#xE3; → ã)
    mensagemFinal = xmlEncodedMessage.replace(/&#x([0-9A-F]+);/gi, (_, hex) =>
      String.fromCharCode(parseInt(hex, 16))
    );
  } else {
    mensagemFinal = parsed; // fallback se não tiver <faultstring>
  }
} else {
  mensagemFinal = rawMessage; // mensagem simples já decodificada
}

return [{ json: { mensagem: mensagemFinal } }];

